// @ts-ignore
import Database from "better-sqlite3";
import { extensionPath } from "@vlcn.io/crsqlite";
const api = {
    open(filename, mode = "c") {
        return new DB(filename || ":memory:");
    },
};
export class DB {
    filename;
    db;
    open;
    siteid;
    constructor(filename) {
        this.filename = filename;
        this.db = new Database(filename);
        this.db.loadExtension(extensionPath);
        this.open = true;
        this.siteid = this.db
            .prepare("SELECT quote(crsql_site_id());")
            .raw()
            .get()[0]
            .replace(/'/g, "");
    }
    execMany(sql) {
        this.db.exec(sql.join(";"));
    }
    exec(sql, bind) {
        if (Array.isArray(bind)) {
            this.db.prepare(sql).run(...bind);
        }
        else {
            this.db.prepare(sql).run();
        }
    }
    execO(sql, bind) {
        if (Array.isArray(bind)) {
            return this.db.prepare(sql).all(...bind);
        }
        else {
            return this.db.prepare(sql).all();
        }
    }
    execA(sql, bind) {
        if (Array.isArray(bind)) {
            return this.db
                .prepare(sql)
                .raw()
                .all(...bind);
        }
        else {
            return this.db.prepare(sql).raw().all();
        }
    }
    onUpdate(cb) {
        throw new Error("Update hook is not currently exposed by better-sqlite3");
    }
    isOpen() {
        return this.open;
    }
    dbFilename() {
        return this.filename;
    }
    openStatementCount() {
        return -1;
    }
    prepare(sql) {
        const ret = this.db.prepare(sql);
        // better-sqlite3 doesn't expose a finalize? hmm..
        ret.finalize = () => { };
        return ret;
    }
    createFunction(name, fn) {
        this.db.function(name, fn);
    }
    savepoint(cb) {
        // better-sqlite3 auto makes a tx a savepoint if nested
        this.transaction(cb);
    }
    transaction(cb) {
        const cb2 = this.db.transaction(cb);
        const ret = cb2();
        if (typeof ret === "object" && typeof ret.then === "function") {
            console.warn("better-sqlite3 should be used synchronously. Passing an async function to transaction will not behave as expected. See https://github.com/vlcn-io/js/issues/104");
        }
        return ret;
    }
    close() {
        this.db.prepare("select crsql_finalize();").run();
        this.db.close();
        this.open = false;
    }
}
export default api;
//# sourceMappingURL=index.js.map

