    flush() {
      const line = buffer.trim();
      if (line.length > 0) {
        try {
          const msg = JSON.parse(line) as Message;
          onMessage(msg);
        } catch {
          // Skip malformed lines
        }
      }
      buffer = '';
    },
  };
}

