1	import net from 'node:net';
2	import {
3	  type Message,
4	  encodeMessage,
5	  createMessageParser,
6	} from './protocol.js';
7	import {
8	  getDbVersion,
9	  getChangeset,
10	  applyChangeset,
11	  getPeerInfo,
12	  updatePeerInfo,
13	} from '../db/queries.js';
14	import { getConfig } from '../lib/config.js';
15	
16	export interface SyncResult {
17	  peerHostname: string;
18	  changesSent: number;
19	  changesReceived: number;
20	}
21	
22	type ClientState =
23	  | 'wait_hello'
24	  | 'wait_changes'
25	  | 'wait_request_changes'
26	  | 'wait_ack'
27	  | 'wait_done'
28	  | 'done';
29	
30	export function syncWithPeer(host: string, port: number): Promise<SyncResult> {
31	  return new Promise((resolve, reject) => {
32	    const config = getConfig();
33	    let state: ClientState = 'wait_hello';
34	    let remotePeerId: string | null = null;
35	    let changesSent = 0;
36	    let changesReceived = 0;
37	
38	    const socket = net.createConnection({ host, port }, () => {
39	      // Connected — send Hello
40	      const dbVersion = getDbVersion();
41	      socket.write(encodeMessage({
42	        type: 'hello',
43	        peerId: config.peerId,
44	        dbVersion,
45	      }));
46	    });
47	
48	    const parser = createMessageParser((msg: Message) => {
49	      try {
50	        switch (state) {
51	          case 'wait_hello': {
52	            if (msg.type !== 'hello') {
53	              socket.destroy(new Error(`Expected hello, got ${msg.type}`));
54	              return;
55	            }
56	            remotePeerId = msg.peerId;
57	
58	            // Send RequestChanges using last known version for this peer
59	            const peerInfo = getPeerInfo(remotePeerId);
60	            const sinceVersion = peerInfo?.last_synced_db_version ?? 0;
61	            socket.write(encodeMessage({
62	              type: 'request_changes',
63	              sinceVersion,
64	            }));
65	
66	            state = 'wait_changes';
67	            break;
68	          }
69	
70	          case 'wait_changes': {
71	            if (msg.type !== 'changes') {
72	              socket.destroy(new Error(`Expected changes, got ${msg.type}`));
73	              return;
74	            }
75	
76	            // Apply received changes
77	            changesReceived = msg.changes.length;
78	            if (msg.changes.length > 0) {
79	              applyChangeset(msg.changes);
80	            }
81	
82	            state = 'wait_request_changes';
83	            break;
84	          }
85	
86	          case 'wait_request_changes': {
87	            if (msg.type !== 'request_changes') {
88	              socket.destroy(new Error(`Expected request_changes, got ${msg.type}`));
89	              return;
90	            }
91	
92	            // Send our changes to the server
93	            const changes = getChangeset(msg.sinceVersion);
94	            const currentVersion = getDbVersion();
95	            changesSent = changes.length;
96	            socket.write(encodeMessage({
97	              type: 'changes',
98	              changes,
99	              fromVersion: msg.sinceVersion,
100	              toVersion: currentVersion,
101	            }));
102	
103	            state = 'wait_ack';
104	            break;
105	          }
106	
107	          case 'wait_ack': {
108	            if (msg.type !== 'ack') {
109	              socket.destroy(new Error(`Expected ack, got ${msg.type}`));
110	              return;
111	            }
112	
113	            // Send our Ack with current db version
114	            const versionAfterSync = getDbVersion();
115	            socket.write(encodeMessage({
116	              type: 'ack',
117	              version: versionAfterSync,
118	            }));
119	
120	            state = 'wait_done';
121	            break;
122	          }
123	
124	          case 'wait_done': {
125	            if (msg.type !== 'done') {
126	              socket.destroy(new Error(`Expected done, got ${msg.type}`));
127	              return;
128	            }
129	
130	            // Update peer info
131	            updatePeerInfo(
132	              remotePeerId!,
